import React, { useState, useEffect, useContext } from 'react';
import { useParams, useNavigate } from 'react-router-dom';
import axios from 'axios';
import { AuthContext } from '../context/AuthContext';
import { FaUsers, FaCog, FaCar, FaMapMarkerAlt, FaCheckCircle } from 'react-icons/fa';
import './CarDetails.css';

const CarDetails = () => {
  const { id } = useParams();
  const navigate = useNavigate();
  const { user } = useContext(AuthContext);
  const [car, setCar] = useState(null);
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    fetchCarDetails();
  }, [id]);

  const fetchCarDetails = async () => {
    try {
      const res = await axios.get(`http://localhost:5000/api/cars/${id}`);
      setCar(res.data.data);
    } catch (error) {
      console.error('Error fetching car details:', error);
    } finally {
      setLoading(false);
    }
  };

  const handleBookNow = () => {
    if (!user) {
      navigate('/login');
      return;
    }
    navigate(`/booking/${id}`);
  };

  if (loading) return <div className="loading">Loading car details...</div>;
  if (!car) return <div className="loading">Car not found</div>;

  return (
    <div className="car-details">
      <div className="container">
        <div className="details-layout">
          <div className="car-gallery">
            <img src={car.images[0] || '/placeholder-car.jpg'} alt={`${car.make} ${car.model}`} className="main-image" />
          </div>

          <div className="car-details-info">
            <div className="details-header">
              <div>
                <h1>{car.make} {car.model}</h1>
                <p className="car-year">{car.year}</p>
              </div>
              <div className="price-box">
                <span className="price">${car.pricePerDay}</span>
                <span className="period">/day</span>
              </div>
            </div>

            <div className="specs-grid">
              <div className="spec-item">
                <FaUsers className="spec-icon" />
                <div>
                  <p className="spec-label">Seating</p>
                  <p className="spec-value">{car.seatingCapacity} Seats</p>
                </div>
              </div>
              <div className="spec-item">
                <FaCog className="spec-icon" />
                <div>
                  <p className="spec-label">Transmission</p>
                  <p className="spec-value">{car.transmission}</p>
                </div>
              </div>
              <div className="spec-item">
                <FaCar className="spec-icon" />
                <div>
                  <p className="spec-label">Fuel Type</p>
                  <p className="spec-value">{car.fuelType}</p>
                </div>
              </div>
              <div className="spec-item">
                <FaMapMarkerAlt className="spec-icon" />
                <div>
                  <p className="spec-label">Location</p>
                  <p className="spec-value">{car.branchId?.city}</p>
                </div>
              </div>
            </div>

            {car.features && car.features.length > 0 && (
              <div className="features-section">
                <h3>Features</h3>
                <ul className="features-list">
                  {car.features.map((feature, index) => (
                    <li key={index}>
                      <FaCheckCircle className="check-icon" />
                      {feature}
                    </li>
                  ))}
                </ul>
              </div>
            )}

            <div className="branch-info">
              <h3>Pickup Location</h3>
              <p>{car.branchId?.name}</p>
              <p>{car.branchId?.address}, {car.branchId?.city}, {car.branchId?.state}</p>
              <p>Phone: {car.branchId?.phone}</p>
            </div>

            <button onClick={handleBookNow} className="btn btn-primary btn-lg">
              Book Now
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

export default CarDetails;
